// 1. Grab items from the FILTER node, not Apify, to guarantee 1:1 index matching
const originalItems = $('Filter: Drop Reposts').all();

// 2. Grab ALL items from Agent 1
const bouncerItems = $('Agent 1: QA Bouncer1').all();

// 3. Create an empty bucket
let badPosts = [];

// 4. Loop through safely
for (let i = 0; i < bouncerItems.length; i++) {

    // Check if the AI graded it as poor
    if (bouncerItems[i].json.text === 'POOR_FORMATTING') {

        // Because we reference the Filter node, index [i] will match perfectly
        // NOTE: Make sure Apify outputs "text" or "content". Standard is usually "text".
        let originalText = originalItems[i].json.text || originalItems[i].json.content;

        if (originalText) {
            badPosts.push(originalText);
        }
    }
}

// 5. Merge all the bad posts together
const mergedText = badPosts.join('\n\n === NEXT POST === \n\n');

// 6. Output the merged text. If badPosts is empty, output a fallback to prevent pipeline crashes.
if (badPosts.length === 0) {
    return [{ json: { combined_posts: "NO_POOR_POSTS_FOUND" } }];
}

return [
  {
    json: {
      combined_posts: mergedText
    }
  }
];
